import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import styled from 'styled-components';
import { useTranslation } from 'react-i18next';

const HeaderContainer = styled.header`
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem;
  background-color: ${({ theme }) => theme.colors.background};
  box-shadow: ${({ theme }) => theme.shadows.sm};
  position: sticky;
  top: 0;
  z-index: 10;
  backdrop-filter: blur(8px);

  @media (prefers-color-scheme: dark) {
    background-color: rgba(18, 18, 18, 0.8);
  }

  @media (max-width: 480px) {
    padding: 0.75rem;
  }
`;

const Logo = styled(Link)`
  font-size: ${({ theme }) => theme.fontSizes.xl};
  font-weight: 700;
  color: ${({ theme }) => theme.colors.primary};
  display: flex;
  align-items: center;
  gap: 1.5rem;

  @media (max-width: 480px) {
    font-size: 3.25rem;
    gap: 0.3rem;
  }
`;

const Avatar = styled.img`
  width: 92px;
  height: 92px;
  border-radius: 50%;
  object-fit: cover;
`;

const UserInfo = styled.div`
  display: flex;
  flex-direction: column;
  justify-content: center;
  margin-left: 12px;
`;

const UserName = styled.div`
  font-size: ${({ theme }) => theme.fontSizes.lg};
  font-weight: 600;
  color: ${({ theme }) => theme.colors.text};
`;

const UserUsername = styled.div`
  font-size: ${({ theme }) => theme.fontSizes.sm};
  color: ${({ theme }) => theme.colors.textLight};
`;

const LanguageSelector = styled.div`
  position: relative;
`;

const LanguageButton = styled.button`
  background: transparent;
  border: 1px solid ${({ theme }) => theme.colors.textLight};
  border-radius: ${({ theme }) => theme.borderRadius.md};
  padding: 0.5rem 1rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: ${({ theme }) => theme.colors.text};
  font-size: ${({ theme }) => theme.fontSizes.sm};

  &:hover {
    background-color: ${({ theme }) => theme.colors.surface};
  }

  @media (prefers-color-scheme: dark) {
    border-color: rgba(255, 255, 255, 0.2);

    &:hover {
      background-color: rgba(255, 255, 255, 0.05);
    }
  }

  @media (max-width: 480px) {
    padding: 0.4rem 0.75rem;
    font-size: 0.8rem;
  }
`;

const LanguageDropdown = styled.div`
  position: absolute;
  top: 100%;
  right: 0;
  margin-top: 0.5rem;
  background-color: ${({ theme }) => theme.colors.background};
  border-radius: ${({ theme }) => theme.borderRadius.md};
  box-shadow: ${({ theme }) => theme.shadows.md};
  overflow: hidden;
  width: 150px;
  z-index: 20;

  @media (prefers-color-scheme: dark) {
    background-color: #1e1e1e;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.3), 0 2px 4px -1px rgba(0, 0, 0, 0.24);
  }

  @media (max-width: 480px) {
    width: 130px;
    right: -5px;
  }
`;

const LanguageOption = styled.button`
  width: 100%;
  text-align: left;
  padding: 0.75rem 1rem;
  background: none;
  border: none;
  color: ${({ theme }) => theme.colors.text};
  font-size: ${({ theme }) => theme.fontSizes.sm};
  cursor: pointer;

  &:hover {
    background-color: ${({ theme }) => theme.colors.surface};
  }

  @media (prefers-color-scheme: dark) {
    &:hover {
      background-color: rgba(255, 255, 255, 0.05);
    }
  }

  @media (max-width: 480px) {
    padding: 0.6rem 0.75rem;
    font-size: 0.8rem;
  }
`;

const Header = ({ avatarPath, userData }) => {
  const { t, i18n } = useTranslation();
  const [isLanguageDropdownOpen, setIsLanguageDropdownOpen] = useState(false);
  const [imageLoaded, setImageLoaded] = useState(false);

  const changeLanguage = (lng) => {
    i18n.changeLanguage(lng);
    setIsLanguageDropdownOpen(false);
  };

  // Формируем URL для аватарки пользователя или дефолтного изображения
  const hasAvatar = Boolean(avatarPath);
  const avatarUrl = hasAvatar 
    ? (avatarPath.startsWith('photos/') ? `/telegram/${avatarPath}` : `/telegram/photos/${avatarPath}`)
    : '/public/images/logo.jpg';

  // Получаем имя и username пользователя
  const userName = userData?.first_name ? 
    (userData.last_name ? `${userData.first_name} ${userData.last_name}` : userData.first_name) : 
    t('guest');
  const userUsername = userData?.username ? `@${userData.username}` : '';

  // Предварительно загружаем изображение
  useEffect(() => {
    const img = new Image();
    img.onload = () => {
      setImageLoaded(true);
    };
    img.src = avatarUrl;
  }, [avatarUrl]);

  if (!imageLoaded) return null;

  return (
    <HeaderContainer>
      <div style={{ display: 'flex', alignItems: 'center' }}>
        {hasAvatar ? (
          <Avatar src={avatarUrl} alt="User Avatar" />
        ) : (
          <Logo to="/">
            <Avatar src={avatarUrl} alt="Logo" />
          </Logo>
        )}
        <UserInfo>
          <UserName>{userName}</UserName>
          {userUsername && <UserUsername>{userUsername}</UserUsername>}
        </UserInfo>
      </div>

      <LanguageSelector>
        <LanguageButton onClick={() => setIsLanguageDropdownOpen(!isLanguageDropdownOpen)}>
          {t('language')}
          <span>{isLanguageDropdownOpen ? '▲' : '▼'}</span>
        </LanguageButton>

        {isLanguageDropdownOpen && (
          <LanguageDropdown>
            <LanguageOption onClick={() => changeLanguage('en')}>
              🇬🇧 {t('english')}
            </LanguageOption>
            <LanguageOption onClick={() => changeLanguage('ru')}>
              🇷🇺 {t('russian')}
            </LanguageOption>
          </LanguageDropdown>
        )}
      </LanguageSelector>
    </HeaderContainer>
  );
};

export default Header;
